    61→static int ldap_is_oid ( const char *str )
    62→{
    63→	int i;
    64→
    65→	if( LDAP_ALPHA( str[0] )) {
    66→		for( i=1; str[i]; i++ ) {
    67→			if( !LDAP_LDH( str[i] )) {
    68→				return 0;
    69→			}
    70→		}
    71→		return 1;
    72→
    73→	} else if LDAP_DIGIT( str[0] ) {
    74→		int dot=0;
    75→		for( i=1; str[i]; i++ ) {
    76→			if( LDAP_DIGIT( str[i] )) {
    77→				dot=0;
    78→
    79→			} else if ( str[i] == '.' ) {
    80→				if( ++dot > 1 ) return 0;
    81→
    82→			} else {
    83→				return 0;
    84→			}
    85→		}
    86→		return !dot;
    87→	}
    88→
    89→	return 0;
    90→}
    91→
    92→static int ldap_is_desc ( const char *str )
    93→{
    94→	int i;
    95→
    96→	if( LDAP_ALPHA( str[0] )) {
    97→		for( i=1; str[i]; i++ ) {
    98→			if( str[i] == ';' ) {
    99→				str = &str[i+1];
   100→				goto options;
   101→			}
   102→
   103→			if( !LDAP_LDH( str[i] )) {
   104→				return 0;
   105→			}
   106→		}
   107→		return 1;
   108→
   109→	} else if LDAP_DIGIT( str[0] ) {
   110→		int dot=0;
   111→		for( i=1; str[i]; i++ ) {
   112→			if( str[i] == ';' ) {
   113→				if( dot ) return 0;
   114→				str = &str[i+1];
   115→				goto options;
   116→			}
   117→
   118→			if( LDAP_DIGIT( str[i] )) {
   119→				dot=0;
   120→
   121→			} else if ( str[i] == '.' ) {
   122→				if( ++dot > 1 ) return 0;
   123→
   124→			} else {
   125→				return 0;
   126→			}
   127→		}
   128→		return !dot;
   129→	}
   130→
   131→	return 0;
   132→
   133→options:
   134→	if( !LDAP_LDH( str[0] )) {
   135→		return 0;
   136→	}
   137→	for( i=1; str[i]; i++ ) {
   138→		if( str[i] == ';' ) {
   139→			str = &str[i+1];
   140→			goto options;
   141→		}
   142→		if( !LDAP_LDH( str[i] )) {
   143→			return 0;
   144→		}
   145→	}
   146→	return 1;
   147→}
